/**
 * Generate E2B firewall config.
 *
 * Data source: https://e2b.dev/docs/api-reference
 *
 * E2B provides secure cloud sandboxes for AI code execution.
 * Uses X-API-Key header authentication.
 * Token format: e2b_ prefix followed by alphanumeric characters.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://e2b.dev/docs/api-reference";
// Token format: e2b_ + 36 alphanumeric chars
const PLACEHOLDER_VALUE = "e2b_CoffeeSafeLocalCoffeeSafeLocalCoffee";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from E2B API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:e2b",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const e2bFirewall = {",
    '  name: "e2b",',
    '  description: "E2B",',
    "  placeholders: {",
    `    E2B_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.e2b.app",',
    "      auth: {",
    "        headers: {",
    '          "X-API-Key": "${{ secrets.E2B_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating E2B firewall config...");
  const ts = generateTypeScript();
  writeOutput("e2b", ts, import.meta.dirname);
}
